/**
 * Returns the nth Fibonacci number.
 * Uses memoization for efficient repeated calls.
 */
const memo = new Map<number, bigint>();

export function fibonacci(n: number): bigint {
  if (n < 0) throw new RangeError('n must be non-negative');
  if (n === 0) return 0n;
  if (n === 1) return 1n;
  if (memo.has(n)) return memo.get(n)!;
  const result = fibonacci(n - 1) + fibonacci(n - 2);
  memo.set(n, result);
  return result;
}

/**
 * Returns the nth Fibonacci number using iteration.
 * More efficient for single large values.
 */
export function fibonacci_iter(n: number): bigint {
  if (n < 0) throw new RangeError('n must be non-negative');
  if (n === 0) return 0n;
  let a = 0n, b = 1n;
  for (let i = 1; i < n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

import { fibonacci, fibonacci_iter } from './fibonacci';
import { expect, test } from 'bun:test';

test('fibonacci base cases', () => {
  expect(fibonacci(0)).toBe(0n);
  expect(fibonacci(1)).toBe(1n);
});

test('fibonacci sequence', () => {
  const expected = [0n, 1n, 1n, 2n, 3n, 5n, 8n, 13n, 21n, 34n];
  for (let i = 0; i < expected.length; i++) {
    expect(fibonacci(i)).toBe(expected[i]);
  }
});

test('fibonacci large value', () => {
  expect(fibonacci(50)).toBe(12586269025n);
});

test('fibonacci_iter matches fibonacci', () => {
  for (let i = 0; i <= 20; i++) {
    expect(fibonacci_iter(i)).toBe(fibonacci(i));
  }
});

test('fibonacci throws on negative', () => {
  expect(() => fibonacci(-1)).toThrow(RangeError);
});

